<?php
function flatten(array $arr, string $prefix=''): array { $out=[]; foreach($arr as $k=>$v){$key=$prefix===''?(string)$k:$prefix.'.'.$k; if(is_array($v)){$out += flatten($v,$key);} else {$out[$key]=$v;}} return $out; }
function setdot(array &$arr, string $path, $value): void { $parts=explode('.',$path); $ref=&$arr; foreach($parts as $i=>$p){ if($i===count($parts)-1){$ref[$p]=$value; return;} if(!isset($ref[$p])||!is_array($ref[$p])) $ref[$p]=[]; $ref=&$ref[$p]; } }
function export_array($v,$i=0){ if(!is_array($v)) return var_export($v,true); $p=str_repeat('    ',$i); $ip=str_repeat('    ',$i+1); if($v===[]) return '[]'; $l=["["]; foreach($v as $k=>$vv){$kk=is_int($k)?$k:var_export((string)$k,true); $l[]=$ip.$kk.' => '.export_array($vv,$i+1).',';} $l[]=$p.']'; return implode("\n",$l);} 
$files=['app.php','admin.php','orders.php','products.php'];
foreach($files as $file){ $enp=__DIR__."/lang/en/$file"; $arp=__DIR__."/lang/ar/$file"; $en=include $enp; $ar=include $arp; $ef=flatten($en); $af=flatten($ar); $all=array_unique(array_merge(array_keys($ef),array_keys($af))); foreach($all as $k){ if(!array_key_exists($k,$ef)) setdot($en,$k,$af[$k]??ucwords(str_replace('_',' ',basename(str_replace('.','/',$k))))); if(!array_key_exists($k,$af)) setdot($ar,$k,$ef[$k]??ucwords(str_replace('_',' ',basename(str_replace('.','/',$k)))));} file_put_contents($enp,"<?php\n\nreturn ".export_array($en).";\n"); file_put_contents($arp,"<?php\n\nreturn ".export_array($ar).";\n"); echo "Synced $file\n"; }
